# Funzione per ottenere i dati estesi di un esagramma
def get_extended_hexagram_data(hexagram_number: int, language: str = "it") -> dict:
    """Restituisce i dati estesi di un esagramma per interpretazioni dettagliate"""
    data = ICHING_EXTENDED.get(hexagram_number, {})
    return data

# Funzione per ottenere il testo di una linea mutevole specifica
def get_moving_line_extended(hexagram_number: int, line_position: int, language: str = "it") -> dict:
    """Restituisce il testo esteso di una linea mutevole specifica"""
    data = ICHING_EXTENDED.get(hexagram_number, {})
    linee = data.get("linee", {})
    return linee.get(line_position, {"testo": "", "significato": ""})
